-- Dumping data for table mediatrack_db.media: ~64 rows (approximately)
INSERT INTO `media` (`id_media`, `judul`, `kategori`, `tahun_rilis`, `sutradara_studio`, `deskripsi`, `created_at`, `image_url`) VALUES
	(1, 'Inception', 'Film', '2010', 'Christopher Nolan', 'Pencuri yang bisa masuk ke dalam mimpi orang lain.', '2026-06-23 09:40:25', 'https://image.tmdb.org/t/p/w500/xlaY2zyzMfkhk0HSC5VUwzoZPU1.jpg'),
	(2, 'Kimi no Na wa', 'Anime', '2016', 'Makoto Shinkai - CoMix Wave Films', 'Dua remaja bertukar tubuh secara misterius melalui mimpi.', '2026-06-23 09:40:25', 'https://cdn.myanimelist.net/images/anime/1823/127994l.jpg'),
	(3, 'Stranger Things', 'Series', '2016', 'The Duffer Brothers', 'Anak-anak ungkap misteri supranatural di kota kecil.', '2026-06-23 09:40:25', 'https://image.tmdb.org/t/p/w500/uOOtwVbSr4QDjAGIifLDwpb2Pdl.jpg'),
	(4, 'Shingeki no Kyojin', 'Anime', '2013', 'Wit Studio', 'Manusia bertahan di balik tembok dari ancaman titan.', '2026-06-23 09:40:25', 'https://cdn.myanimelist.net/images/anime/10/47347l.jpg'),
	(5, 'The Dark Knight', 'Film', '2008', 'Christopher Nolan', 'Batman menghadapi Joker yang kacaukan Gotham City.', '2026-06-23 09:40:25', 'https://image.tmdb.org/t/p/w500/qJ2tW6WMUDux911r6m7haRef0WH.jpg'),
	(6, 'Steins; Gate', 'Anime', '2011', 'White Fox', 'Ilmuwan Eksentrik yang bermain dengan waktu, namun ada hal besar menantinya', '2026-06-25 10:00:07', 'https://cdn.myanimelist.net/images/anime/1935/127974l.jpg'),
	(7, 'Steins; Gate 0', 'Anime', '2018', 'White Fox', 'Setelah berbagai rintangan, Okabe berjalan dengan penyesalan dan rasa bersalah menyertainya', '2026-06-26 16:59:04', 'https://cdn.myanimelist.net/images/anime/1375/93521l.jpg'),
	(8, 'Naruto', 'Anime', '2002', 'Pierrot', 'Naruto (2002) menceritakan Naruto Uzumaki, seorang ninja muda yang dijauhi karena menjadi wadah Rubah Ekor Sembilan, namun bermimpi menjadi Hokage agar diakui oleh semua orang. Setelah menjadi ninja, ia bergabung dalam Tim 7 bersama Sasuke dan Sakura di bawah bimbingan Kakashi. Mereka menjalani berbagai misi berbahaya sambil menghadapi konflik, membangun persahabatan, dan menemukan arti sebenarnya dari menjadi seorang ninja.', '2026-06-29 10:10:59', 'https://cdn.myanimelist.net/images/anime/1141/142503l.jpg'),
	(9, 'Steins;Gate: Kyoukaimenjou no Missing Link - Divide By Zero', 'Anime', '2015', 'White Fox', 'Setelah mencapai titik batas ketahanan emosionalnya, Rintarou Okabe menolak untuk terus membantu penjelajah waktu Suzuha Amane dalam misinya mencegah Perang Dunia III, karena ia yakin bahwa segala upaya lebih lanjut untuk menyelamatkan Makise Kurisu akan sia-sia. Tak lama kemudian, Okabe menanggalkan persona "ilmuwan gila"-nya dan menjalani kehidupan layaknya mahasiswa biasa.', '2026-07-01 02:12:38', 'https://cdn.myanimelist.net/images/anime/7/77324l.jpg'),
	(10, 'Samurai Champloo', 'Anime', '2004', 'Manglobe', 'Kisah tiga orang asing di era Edo: Mugen (penjahat jalanan dengan gaya bertarung akrobatik), Jin (ronin yang tenang dan tradisional), serta Fuu (pelayan kedai teh). Mereka melakukan perjalanan lintas Jepang untuk mencari "samurai yang berbau bunga matahari" demi mengungkap rahasia masa lalu Fuu', '2026-07-01 02:29:23', 'https://cdn.myanimelist.net/images/anime/1763/144789l.jpg'),
	(11, 'Toradora!', 'Anime', '2008', 'J.C Staff', 'Ryuji Takasu, siswa berhati lembut yang sering ditakuti karena memiliki wajah garang, dan Taiga Aisaka, gadis bertubuh mungil namun sangat agresif yang dijuluki "Harimau Berantai". Mereka berdua bekerja sama untuk saling membantu menyatakan cinta kepada sahabat masing-masing, tetapi akhirnya malah saling jatuh cinta seiring berjalannya waktu', '2026-07-01 02:32:48', 'https://cdn.myanimelist.net/images/anime/13/22128l.jpg'),
	(12, 'Death Note', 'Anime', '2006', 'Madhouse', 'Light Yagami, seorang siswa SMA jenius yang menemukan buku catatan supernatural bernama Death Note milik dewa kematian Ryuk. Light menggunakan kekuatan buku tersebut untuk membunuh para penjahat dan memproklamirkan dirinya sebagai "Kira" untuk menciptakan dunia baru yang bersih dari kejahatan', '2026-07-01 02:35:15', 'https://cdn.myanimelist.net/images/anime/1079/138100l.jpg'),
	(13, 'Danshi Koukousei no Nichijou', 'Anime', '2012', 'Sunrise', 'Anime komedi slice-of-life yang mengikuti keseharian tiga sahabat: Tadakuni, Hidenori, dan Yoshitake, beserta teman-teman sekolah mereka di SMA khusus laki-laki Sanada Utara', '2026-07-01 02:38:28', 'https://cdn.myanimelist.net/images/anime/3/33257l.jpg'),
	(14, 'Mr. Robot', 'Series', '2015', 'Sam Esmail', 'Drama kontemporer dan resonan budaya tentang seorang programmer muda, Elliot, yang menderita gangguan anti-sosial yang melemahkan dan memutuskan bahwa ia hanya dapat terhubung dengan orang-orang dengan meretasnya. Dia menggunakan keterampilannya sebagai senjata untuk melindungi orang-orang yang dia sayangi. Elliot akan menemukan dirinya di persimpangan antara sebuah perusahaan cybersecurity tempat dia bekerja dan organisasi-organisasi dunia bawah yang merekrutnya untuk menjatuhkan perusahaan Amerika.', '2026-07-01 02:42:27', 'https://image.tmdb.org/t/p/w500/kv1nRqgebSsREnd7vdC2pSGjpLo.jpg'),
	(15, 'Mononoke Hime', 'Anime', '1997', 'Hayao Miyazaki - Ghibli', 'Ashitaka, seorang pangeran dari orang Emishi yang menghilang, dikutuk oleh dewa babi hutan yang dijelek-jelekkan dan harus melakukan perjalanan ke barat untuk menemukan obatnya. Sepanjang jalan, dia bertemu San, seorang wanita manusia muda yang berjuang untuk melindungi hutan, dan Lady Eboshi, yang mencoba menghancurkannya. Ashitaka harus menemukan cara untuk membawa keseimbangan dalam konflik ini.', '2026-07-01 02:46:48', 'https://cdn.myanimelist.net/images/anime/1355/147277l.jpg'),
	(16, 'The Imitation Game', 'Film', '2014', 'Morten Tyldum', 'Berdasarkan kisah kehidupan nyata cryptanalyst legendaris Alan Turing, film ini menggambarkan perlombaan menggigit kuku melawan waktu oleh Turing dan tim pemecah kode briliannya di Sekolah Kode dan Cypher Pemerintah Inggris yang sangat rahasia di Bletchley Park, selama hari-hari paling gelap Perang Dunia II.', '2026-07-01 02:52:18', 'https://image.tmdb.org/t/p/w500/zSqJ1qFq8NXFfi7JeIYMlzyR0dx.jpg'),
	(17, 'True Detective', 'Series', '2014', 'Nic Pizzolatto & Issa López', 'Sebuah serial antologi detektif kepolisian Amerika yang menggunakan berbagai alur waktu di mana investigasi tampaknya mengungkap rahasia pribadi dan profesional dari mereka yang terlibat, baik di dalam maupun di luar hukum.', '2026-07-01 02:54:37', 'https://image.tmdb.org/t/p/w500/dC7jkj2g1aU8sxKqM6D4g44xA6w.jpg'),
	(18, 'Dark', 'Series', '2017', 'Baran bo Odar & Jantje Friese', 'Hilangnya seorang anak membuat empat keluarga berburu jawaban saat mereka menggali misteri rumit yang melibatkan tiga generasi.', '2026-07-01 02:56:52', 'https://image.tmdb.org/t/p/w500/1DLjjvSWMYo17B7wuz6YikB96hH.jpg'),
	(19, 'Monster', 'Anime', '2004', 'Madhouse', 'Kenzou Tenma, seorang ahli bedah otak Jepang di Jerman, mendapati hidupnya berantakan setelah terlibat dengan seorang psikopat yang dulunya adalah pasiennya.', '2026-07-01 03:02:25', 'https://cdn.myanimelist.net/images/anime/10/18793l.jpg'),
	(20, 'Death Parade', 'Anime', '2015', 'Madhouse', 'Ada tempat setelah kematian yang bukan surga maupun neraka. Sebuah bar yang memberimu satu kesempatan untuk menang. Kau tak bisa pergi sampai permainan selesai, dan ketika selesai, hidupmu mungkin juga akan berakhir.', '2026-07-01 03:08:49', 'https://cdn.myanimelist.net/images/anime/5/71553l.jpg'),
	(21, '86 Eighty-Six', 'Anime', '2021', 'A-1 Pictures', 'Disebut “Juggernaut,” ini adalah drone tempur tak berawak yang dikembangkan oleh Republik San Magnolia sebagai jawaban atas serangan drone tak berawak otonom dari Kekaisaran Giad yang berdekatan, “Legion”. Tapi mereka hanya tak berawak namanya. Kenyataannya, mereka diujicobakan oleh Delapan Puluh Enam — yang dianggap kurang manusiawi dan diperlakukan hanya sebagai alat. Bertekad untuk mencapai tujuan misteriusnya sendiri, Shin, kapten Skuadron Ujung Tombak, yang terdiri dari Delapan Puluh Enam, terus berperang tanpa harapan di medan perang di mana hanya kematian yang menunggunya.', '2026-07-01 03:11:56', 'https://cdn.myanimelist.net/images/anime/1987/117507l.jpg'),
	(22, 'Hajime no Ippo', 'Anime', '2000', 'Madhouse', 'Makunouchi Ippo adalah seorang siswa SMA biasa di Jepang. Karena dia menghabiskan sebagian besar waktunya jauh dari sekolah membantu ibunya menjalankan bisnis keluarga, dia tidak bisa menikmati masa mudanya seperti kebanyakan remaja. Selalu menjadi target intimidasi di sekolah (bisnis memancing keluarga memberinya bau yang berbeda), kehidupan Ippo adalah salah satu kesulitan. Salah satu sesi intimidasi sepulang sekolah ini mengubah hidup Ippo menjadi lebih baik, karena ia diselamatkan oleh seorang petinju bernama Takamura. Dia memutuskan untuk mengikuti jejak Takamura dan berlatih menjadi petinju, memberikan arah dan tujuan hidupnya. Jalan Ippo untuk menyempurnakan kecakapan petarungnya baru saja dimulai...', '2026-07-01 03:13:56', 'https://cdn.myanimelist.net/images/anime/4/86334l.jpg'),
	(23, 'Mr. Bean', 'Series', '1990', 'Richard Curtis & Rowan Atkinson', 'Mr. Bean mengubah tugas-tugas sederhana sehari-hari menjadi situasi kacau dan akan membuat Anda tertawa terbahak-bahak saat ia menciptakan kekacauan di mana pun ia berada.', '2026-07-01 03:16:34', 'https://image.tmdb.org/t/p/w500/pUNQV35kDaKuejnXGNiUeEBurNE.jpg'),
	(24, 'Gintama', 'Anime', '2006', 'Sunrise', 'Di dunia di mana alien telah menginvasi Jepang pada Periode Edo, gedung pencakar langit, kereta api, dan sepeda motor telah menggantikan kehidupan sederhana penduduk Bumi. Namun, ada seorang pria yang masih membawa jiwa seorang samurai, Gintoki Sakata, atau dikenal juga sebagai Yorozuya Gin-san. Seceroboh apa pun dia, Gintoki memiliki tekad sendiri dan siap menghadapi tantangan apa pun bersama rekan-rekannya.', '2026-07-01 03:18:26', 'https://cdn.myanimelist.net/images/anime/10/73274l.jpg'),
	(25, 'Takopii no Genzai', 'Anime', '2025', 'Enishiya', 'Takopi si alien ceria bertemu Shizuka, gadis Bumi nan malang. Saat Takopi kembali ke masa lalu demi menyelamatkan Shizuka, niat baiknya memicu kekacauan yang lebih besar.', '2026-07-01 03:22:33', 'https://cdn.myanimelist.net/images/anime/1444/146894l.jpg'),
	(26, 'Shangri-La Frontier', 'Anime', '2023', 'C2C', '"Kapan terakhir kali aku memainkan permainan yang tidak jelek?" Ini adalah dunia dalam waktu dekat di mana game yang menggunakan tampilan layar tergolong retro. Apa pun yang tidak dapat mengikuti teknologi VR yang canggih disebut "permainan sampah", dan Anda akan melihat banyak sekali permainan sampah yang bermunculan. Mereka yang mengabdikan hidupnya untuk menyelesaikan game-game ini disebut "pemburu game sampah", dan Rakuro Hizutome adalah salah satunya. Game yang dia pilih untuk ditangani selanjutnya adalah Shangri-La Frontier, sebuah "game tingkat dewa" yang memiliki total tiga puluh juta pemain. Teman daring, Dunia yang luas, Pertemuan dengan saingan ini mengubah nasib Rakuro dan semua pemain lainnya! Kisah petualangan game terbaik oleh pemain "game omong kosong" terkuat dimulai sekarang!', '2026-07-01 03:25:06', 'https://cdn.myanimelist.net/images/anime/1500/139931l.jpg'),
	(27, 'Perfect Days', 'Film', '2026', 'Wim Wenders', 'Hirayama merasa puas dengan kehidupannya sebagai petugas kebersihan toilet di Tokyo. Di luar rutinitasnya yang terstruktur, ia menyukai musik kaset, buku, dan memotret pepohonan. Melalui pertemuan-pertemuan tak terduga, ia merenungkan tentang menemukan keindahan di dunia.', '2026-07-01 03:27:11', 'https://image.tmdb.org/t/p/w500/mjEk5Wwx6TYVqw29zSaUHclMIgp.jpg'),
	(28, 'Uncut Gems', 'Film', '2019', 'Benny Safdie, Josh Safdie & Ronald Bronstein', 'Film thriller criminal yang berkisah tentang Howard Ratner yang diperankan Adam Sandler. Howard Ratner adalah seorang pengusaha berlian karismatik asal Kota New York yang berusaha untuk mencari skor tinggi', '2026-07-01 03:31:56', 'https://image.tmdb.org/t/p/w500/6XN1vxHc7kUSqNWtaQKN45J5x2v.jpg'),
	(29, 'Harakiri', 'Film', '1962', 'Masaki Kobayashi', 'Down-on-nya-keberuntungan veteran Tsugumo Hanshirō memasuki halaman Rumah Iyi makmur. Pengangguran, dan tanpa keluarga, ia berharap untuk menemukan tempat untuk melakukan seppuku—dan detik yang layak untuk memberikan coup de grâce dalam ritual bunuh dirinya. Konselor senior untuk klan Iyi mempertanyakan tekad dan integritas ronin, mencurigai Hanshirō mencari amal daripada akhir yang terhormat. Berikut ini adalah sepasang cerita yang saling terkait yang mengungkap perbedaan antara kehormatan dan rasa hormat, dan berjanji untuk mengkaji landasan legendaris kode Samurai.', '2026-07-01 03:33:54', 'https://image.tmdb.org/t/p/w500/zK7HsOC7QxW1ldKIeFG8YJ5F2Eb.jpg'),
	(30, 'The Social Network', 'Film', '2010', 'David Fincher', 'Pada tahun 2003, sarjana Harvard dan programmer komputer Mark Zuckerberg mulai mengerjakan konsep baru yang akhirnya berubah menjadi jejaring sosial global yang dikenal sebagai Facebook. Enam tahun kemudian, Mark adalah salah satu miliarder termuda yang pernah ada, namun kesuksesannya yang belum pernah terjadi sebelumnya menyebabkan komplikasi pribadi dan hukum ketika ia menerima dua tuntutan hukum, salah satunya melibatkan mantan temannya.', '2026-07-01 03:36:06', 'https://image.tmdb.org/t/p/w500/n0ybibhJtQ5icDqTp8eRytcIHJx.jpg'),
	(31, 'The Truman Show', 'Film', '1998', 'Peter Weir', 'Di kota tepi pantai yang sempurna, seorang penjual asuransi mulai menyadari bahwa seluruh keberadaannya mungkin dipentaskan dan diamati oleh banyak penonton tak terlihat sebagai bagian dari acara TV realitas real-time yang sudah berjalan lama.', '2026-07-01 03:37:34', 'https://image.tmdb.org/t/p/w500/vuza0WqY239yBXOadKlGwJsZJFE.jpg'),
	(32, 'Django Unchained', 'Film', '2012', 'Quentin Tarantino', 'Ditemani oleh pemburu hadiah asal Jerman, seorang budak yang dibebaskan bernama Django melintasi Amerika demi membebaskan istrinya dari pemilik perkebunan yang sadis.', '2026-07-01 03:40:29', 'https://image.tmdb.org/t/p/w500/7oWY8VDWW7thTzWh3OKYRkWUlD5.jpg'),
	(33, 'Kill Bill Vol. 1', 'Film', '2003', 'Quentin Tarantino', 'Seorang pembunuh yang Sedang hamil, dengan nama sandi The Bride, mengalami koma selama empat tahun setelah mantan bosnya, Bill, menyerangnya secara brutal. Ketika dia bangun, dia bertekad untuk membalas dendam padanya dan rekan-rekannya.', '2026-07-01 03:43:53', 'https://image.tmdb.org/t/p/w500/v7TaX8kXMXs5yFFGR41guUDNcnB.jpg'),
	(34, 'Kill Bill Vol. 2', 'Film', '2004', 'Quentin Tarantino', 'Sang Mempelai Wanita melanjutkan upaya balas dendamnya terhadap mantan bos dan kekasihnya, Bill, penjaga pintu yang penyendiri, Budd, dan Elle yang bermata satu dan pengkhianat.', '2026-07-01 03:44:55', 'https://image.tmdb.org/t/p/w500/2yhg0mZQMhDyvUQ4rG1IZ4oIA8L.jpg'),
	(35, 'Schindler\'s List', 'Film', '1993', 'Steven Spielberg', 'Kisah nyata tentang bagaimana pengusaha Oskar Schindler menyelamatkan lebih dari seribu nyawa orang Yahudi dari Nazi saat mereka bekerja sebagai budak di pabriknya selama Perang Dunia II.', '2026-07-01 03:46:31', 'https://image.tmdb.org/t/p/w500/sF1U4EUQS8YHUYjNl3pMGNIQyr0.jpg'),
	(36, 'Inglourious Basterds', 'Film', '2009', 'Quentin Tarantino', 'Di Prancis yang diduduki Nazi selama Perang Dunia II, sekelompok tentara Yahudi-Amerika yang dikenal sebagai "The Basterds" dipilih secara khusus untuk menyebarkan ketakutan di seluruh Reich Ketiga dengan menguliti dan membunuh Nazi secara brutal. The Basterds, yang dipimpin oleh Letnan Aldo Raine, segera bertemu dengan seorang gadis remaja Yahudi-Prancis yang menjalankan bioskop di Paris yang menjadi sasaran para tentara.', '2026-07-01 03:50:10', 'https://image.tmdb.org/t/p/w500/sAHh7weBXjH0qtiQP3Z7bIECoxf.jpg'),
	(37, 'Jatuh Cinta Seperti di Film-Film', 'Film', '2023', 'Yandy Laurens', 'Bagus, seorang penulis skenario, bertemu kembali dengan teman SMA dan pujaan hatinya, Hana, yang masih berduka atas kehilangan suaminya. Dia ingin meyakinkan Hana untuk jatuh cinta lagi, seperti di film-film.', '2026-07-01 03:52:34', 'https://image.tmdb.org/t/p/w500/nvCFJIj4cJXZeOwGU0sns0g03K1.jpg'),
	(38, '1 Kakak 7 Ponakan', 'Film', '2025', 'Yandy Laurens', 'Setelah kematian mendadak kakak perempuannya dan suaminya, seorang arsitek muda yang sedang berjuang tiba-tiba menjadi "orang tua tunggal" bagi keponakan-keponakannya. Ketika kesempatan untuk kehidupan yang lebih baik muncul, ia harus memilih antara kehidupan cintanya, kariernya, atau keluarganya.', '2026-07-01 03:54:32', 'https://image.tmdb.org/t/p/w500/xBOrUqfMyCEdfz0B6OaOs8RwAbb.jpg'),
	(39, 'Perfect Blue', 'Anime', '1998', 'Satoshi Kon - Madhouse', 'Bintang pop yang sedang naik daun, Mima Kirigoe, berhenti bernyanyi untuk mengejar karier sebagai aktris. Setelah ia mendapatkan peran dalam sebuah acara detektif populer, para penanggung jawab dan kolaboratornya mulai ditemukan tewas dibunuh. Dihantui perasaan bersalah dan dihantui oleh bayangan dirinya di masa lalu, realitas dan fantasi Mima bercampur menjadi paranoia yang mencekam.', '2026-07-01 03:57:27', 'https://image.tmdb.org/t/p/w500/6WTiOCfDPP8XV4jqfloiVWf7KHq.jpg'),
	(40, 'Oppenheimer', 'Film', '2023', 'Christopher Nolan', 'Kisah J. Peran Robert Oppenheimer dalam pengembangan bom atom selama Perang Dunia II.', '2026-07-01 04:00:19', 'https://image.tmdb.org/t/p/w500/8Gxv8gSFCU0XGDykEGv7zR1n2ua.jpg'),
	(41, 'No Country for Old Men', 'Film', '2007', 'Ethan Coen & Joel Coen', 'Llewelyn Moss menemukan mayat, uang 2 juta dolar, dan tumpukan heroin di gurun Texas, tetapi pembunuh berantai Anton Chigurh datang mencarinya, dengan sheriff setempat Ed Tom Bell mengejarnya. Peran mangsa dan predator menjadi kabur saat pengejaran uang dan keadilan yang penuh kekerasan bertabrakan.', '2026-07-01 04:02:02', 'https://image.tmdb.org/t/p/w500/uB7RDZby43Wvu8SKGHHTwGyTDBX.jpg'),
	(42, 'Interstellar', 'Film', '2014', 'Christopher Nolan & Jonathan Nolan', 'Antarbintang mencatat petualangan sekelompok penjelajah yang memanfaatkan lubang cacing yang baru ditemukan untuk melampaui batasan perjalanan ruang angkasa manusia dan menaklukkan jarak yang luas yang terlibat dalam pelayaran antarbintang.', '2026-07-01 04:03:54', 'https://image.tmdb.org/t/p/w500/yQvGrMoipbRoddT0ZR8tPoR7NfX.jpg'),
	(43, 'Chainsaw Man', 'Anime', '2022', 'MAPPA', 'Denji memiliki mimpi sederhana—untuk hidup bahagia dan damai, menghabiskan waktu bersama gadis yang disukainya. Namun, kenyataan jauh berbeda, karena Denji dipaksa oleh yakuza untuk membunuh iblis demi melunasi hutangnya yang menumpuk. Dengan menggunakan iblis peliharaannya, Pochita, sebagai senjata, ia siap melakukan apa saja demi sedikit uang.', '2026-07-01 04:05:26', 'https://cdn.myanimelist.net/images/anime/1803/132254l.jpg'),
	(44, 'Chainsaw Man Movie: Reze-hen', 'Anime', '2025', 'MAPPA', 'Dalam perang brutal antara iblis, pemburu, dan musuh rahasia, seorang gadis misterius bernama Reze telah memasuki dunia Denji, dan dia menghadapi pertempuran paling mematikan yang pernah ada, didorong oleh cinta di dunia di mana bertahan hidup tidak mengenal aturan.', '2026-07-01 04:08:04', 'https://cdn.myanimelist.net/images/anime/1763/150638l.jpg'),
	(45, 'Dr. Stone', 'Anime', '2019', 'TMS Entertainment', 'Pada suatu hari yang menentukan, seluruh umat manusia membeku karena kilatan cahaya yang menyilaukan. Setelah beberapa milenium, Taiju, seorang siswa SMA, terbangun dan mendapati dirinya tersesat di dunia patung. Namun, dia tidak sendirian! Temannya yang menyukai sains, Senku, telah aktif selama beberapa bulan dan dia memiliki rencana besar—untuk memulai kembali peradaban dengan kekuatan sains.', '2026-07-01 04:09:50', 'https://cdn.myanimelist.net/images/anime/1613/102576l.jpg'),
	(46, 'No Game No Life', 'Anime', '2014', 'Madhouse', 'Bosan dengan kehidupan dan menganggap dunia nyata hanyalah permainan jelek, saudara kandung yang cerdas, Sora dan Shiro, telah menarik diri ke dunia fantasi mereka sendiri yang penuh dengan video game. Namun, suatu hari mereka mendapati diri mereka dipanggil ke dunia lain oleh seorang anak laki-laki yang menyebut dirinya “Tuhan,” kemampuan mereka akan diuji! Sekarang tidak hanya nasib mereka — tetapi nasib seluruh umat manusia — akan ditentukan oleh serangkaian permainan yang mungkin merupakan permainan tersulit yang pernah dihadapi para super jenius ini!', '2026-07-01 04:13:32', 'https://cdn.myanimelist.net/images/anime/1074/111944l.jpg'),
	(47, 'Hunter x Hunter (2011)', 'Anime', '2011', 'Madhouse', 'Suatu hari Gon Freecss yang berusia dua belas tahun menemukan bahwa ayah yang selalu diberi tahu bahwa ayahnya sudah mati, masih hidup dan sehat. Ayahnya, Ging, adalah seorang Pemburu — anggota elit masyarakat dengan izin untuk pergi ke mana pun atau melakukan hampir semua hal. Gon, yang bertekad untuk mengikuti jejak ayahnya, memutuskan untuk mengambil Ujian Hunter dan akhirnya menemukan ayahnya untuk membuktikan dirinya sebagai seorang Pemburu dengan haknya sendiri. Namun di tengah jalan, dia belajar bahwa ada lebih banyak untuk menjadi seorang Pemburu daripada yang diperkirakan sebelumnya, dan tantangan yang harus dia hadapi dianggap sebagai yang terberat di dunia.', '2026-07-01 04:14:53', 'https://cdn.myanimelist.net/images/anime/1337/99013l.jpg'),
	(48, 'Hunter x Hunter (1999)', 'Anime', '1999', 'Nippon Animation', 'Gon Freecss menemukan bahwa ayahnya, yang selama ini dianggap telah meninggal, ternyata masih hidup. Ging adalah seorang Hunter terkenal: individu yang telah membuktikan dirinya sebagai anggota elit umat manusia. Gon bertekad untuk mengikuti jejak ayahnya, dan lulus Ujian Hunter yang ketat.', '2026-07-01 04:16:41', 'https://cdn.myanimelist.net/images/anime/1305/132237l.jpg'),
	(49, 'Re:Zero kara Hajimeru Isekai Seikatsu', 'Anime', '2016', 'White Fox', 'Natsuki Subaru, seorang siswa SMA biasa, sedang dalam perjalanan pulang dari minimarket ketika ia mendapati dirinya dipindahkan ke dunia lain. Saat ia tersesat dan bingung di dunia baru di mana ia bahkan tidak tahu arah kiri dan kanan, satu-satunya orang yang mengulurkan tangan kepadanya adalah seorang gadis cantik berambut perak. Bertekad untuk membalas budi gadis itu karena telah menyelamatkannya dari keputusasaan, Subaru setuju untuk membantu gadis itu menemukan sesuatu yang dicarinya.', '2026-07-01 04:18:24', 'https://cdn.myanimelist.net/images/anime/1534/134863l.jpg'),
	(50, 'Yahari Ore no Seishun Love Comedy wa Machigatteiru.', 'Anime', '2013', 'Brain\'s Base', 'Jadi, apa sebenarnya yang akan terjadi ketika Hachiman Hikigaya, seorang siswa SMA yang penyendiri tanpa teman, tidak tertarik untuk berteman, dan percaya bahwa pengalaman SMA orang lain yang konon hebat hanyalah khayalan atau kebohongan belaka, dipaksa oleh seorang anggota fakultas yang bermaksud baik untuk bergabung dengan "Klub Layanan Sukarelawan" yang hanya beranggotakan satu orang dan dipimpin oleh Yukino Yukinoshita, yang cerdas, menarik, dan umumnya menganggap semua orang di sekolahnya lebih rendah darinya?', '2026-07-01 04:21:37', 'https://cdn.myanimelist.net/images/anime/11/49459l.jpg'),
	(51, 'Youkoso Jitsuryoku Shijou Shugi no Kyoushitsu e', 'Anime', '2017', 'Lerche', 'Di permukaan, SMA Koudo Ikusei adalah sebuah utopia. Para siswa menikmati kebebasan yang tak tertandingi, dan peringkatnya tinggi di Jepang. Namun, kenyataannya kurang ideal. Empat kelas, A sampai D, diurutkan berdasarkan prestasi, dan hanya kelas teratas yang menerima perlakuan yang menguntungkan. Kiyotaka Ayanokouji adalah siswa Kelas D, tempat sekolah membuang yang terburuk. Di sana dia bertemu dengan Suzune Horikita yang tidak ramah, yang percaya dia ditempatkan di Kelas D karena kesalahan dan keinginan untuk naik ke Kelas A, dan idola kelas yang tampaknya ramah Kikyou Kushida, yang bertujuan untuk mendapatkan teman sebanyak mungkin.', '2026-07-01 04:24:15', 'https://cdn.myanimelist.net/images/anime/5/86830l.jpg'),
	(52, 'Meitantei Conan', 'Anime', '1996', 'TMS Entertainment', 'Putra dari penulis misteri terkenal dunia, Jimmy Kudo, telah mencapai ketenarannya sendiri dengan membantu polisi setempat sebagai detektif magang. Dia selalu mampu memecahkan kasus kriminal tersulit sekalipun menggunakan kecerdasan dan daya penalaran logisnya.', '2026-07-01 04:27:53', 'https://cdn.myanimelist.net/images/anime/7/75199l.jpg'),
	(53, 'Just Because!', 'Anime', '2017', 'PINE JAM', 'Di penghujung semester kedua tahun ketiga SMA, empat siswa bersiap untuk wisuda dan merasakan akhir dari kehidupan sekolah menengah mereka. Namun, hal itu sedikit berubah dengan kedatangan seorang siswa pindahan.', '2026-07-01 04:29:30', 'https://cdn.myanimelist.net/images/anime/10/88234l.jpg'),
	(54, 'ReLIFE', 'Anime', '2016', 'TMS Entertainment', 'Arata Kaizaki (27) berhenti dari pekerjaannya setelah lulus hanya dalam waktu tiga bulan. Hidupnya tidak berjalan dengan baik setelah itu. Sekarang orang tuanya mengancam untuk berhenti mengirim uang, dan ingin dia kembali ke negara itu. Dia tidak memiliki teman atau pacar untuk berbagi masalahnya dengan... saat dia mencapai titik terendah seorang pria aneh bernama Ryou Yoake muncul. Ia mengajak Arata untuk mengikuti program rehabilitasi masyarakat untuk NEET bernama ReLife. Program ini menggunakan obat misterius untuk membuatnya terlihat lebih muda, dan mengirimnya kembali ke sekolah menengah selama setahun...', '2026-07-01 04:31:42', 'https://cdn.myanimelist.net/images/anime/3/82149l.jpg'),
	(55, 'Kaze ga Tsuyoku Fuiteiru', 'Anime', '2018', 'Production I.G', 'Kakeru, mantan pelari elit di sekolah menengah, dikejar karena mencuri makanan. Dia diselamatkan oleh mahasiswa Universitas Kansei Haiji, yang juga seorang pelari. Haiji membujuk Kakeru untuk tinggal di apartemen tua "Chikuseisou" di mana dia berencana untuk bekerja sama dengan sesama penghuni untuk memasuki Hakone Ekiden Marathon, salah satu perlombaan universitas paling terkemuka di Jepang. Kakeru segera mengetahui bahwa semua penghuni kecuali Haiji dan dirinya sendiri adalah pemula.', '2026-07-01 04:35:05', 'https://cdn.myanimelist.net/images/anime/1936/129119l.jpg'),
	(56, 'Dragon Ball', 'Anime', '1986', 'Toei Animation', 'Dahulu kala di pegunungan, seorang master pertempuran yang dikenal sebagai Gohan menemukan seorang bocah aneh yang ia beri nama Goku. Gohan membesarkannya dan melatih Goku dalam seni bela diri sampai dia mati. Bocah muda dan sangat kuat itu sendirian, tetapi mudah dikelola. Kemudian suatu hari, Goku bertemu dengan seorang gadis remaja bernama Bulma, yang pencariannya untuk bola naga membawanya ke rumah Goku. Bersama-sama, mereka berangkat untuk menemukan ketujuh bola naga dalam sebuah petualangan yang akan mengubah hidup Goku selamanya. Lihat bagaimana Goku bertemu teman-teman seumur hidupnya Bulma, Yamcha, Krillin, Master Roshi dan banyak lagi.', '2026-07-01 04:36:59', 'https://cdn.myanimelist.net/images/anime/1887/92364.jpg'),
	(57, 'Hellsing', 'Anime', '2001', 'Gonzo', 'Vampir ada. Merupakan tugas Hellsing, sebuah organisasi yang disponsori oleh pemerintah Inggris, untuk menyembunyikan fakta menakutkan tersebut dan melindungi masyarakat yang tidak menyadarinya.\n\nAkhir-akhir ini, aktivitas vampir telah meningkat dan penyebabnya lebih mengkhawatirkan daripada apa pun yang bisa mereka bayangkan.', '2026-07-01 04:38:27', 'https://cdn.myanimelist.net/images/anime/10/19956l.jpg'),
	(58, 'Serial Experiments Lain', 'Anime', '1998', 'Triangle Staff', 'Lain—yang terdorong oleh bunuh diri mendadak seorang teman sekelas—masuk ke Wired dan langsung tersesat dalam kumpulan halusinasi, ingatan, dan jiwa-jiwa yang saling terhubung yang membingungkan.', '2026-07-01 04:41:13', 'https://cdn.myanimelist.net/images/anime/1718/91550l.jpg'),
	(59, 'Haibane Renmei', 'Anime', '2002', 'Radix', 'Mimpi jatuh dari langit...dan kemudian kelahiran. Rakka lahir dari kepompong besar ke dalam Rumah Tua, disambut oleh sekelompok makhluk betina dengan sayap kecil di punggung dan lingkaran cahaya bersinar di atas kepala. Segera sayap Rakka sendiri tumbuh, lingkaran cahaya ditempatkan di kepalanya dan dia diberitahu bahwa dia harus bekerja di kota terdekat Grie. Dia segera menyadari bahwa kota dan seluruh dunia tempat mereka tinggal terkurung di balik Tembok, sebuah tembok tinggi yang tidak dapat ditembus sehingga tidak ada seorang pun kecuali Toga misterius yang diizinkan keluar.', '2026-07-01 04:43:18', 'https://cdn.myanimelist.net/images/anime/9/13134l.jpg'),
	(60, 'Mushishi', 'Anime', '2005', 'Artland', 'Ginko, seorang ahli Mushi, berkelana dari satu tempat ke tempat lain untuk meneliti Mushi dan membantu orang-orang yang menderita karenanya.', '2026-07-01 04:44:42', 'https://cdn.myanimelist.net/images/anime/2/73862l.jpg'),
	(61, 'Hellsing Ultimate', 'Anime', '2006', 'Madhouse, Satelight, Graphinica', 'Selama lebih dari seabad, Organisasi Hellsing yang misterius telah secara diam-diam melindungi Kekaisaran Inggris dari makhluk undead. Ketika Sir Integra Hellsing berhasil menjadi kepala organisasi, ia juga mewarisi senjata pamungkas melawan musuh supernatural ini: Alucard, seorang vampir pemberontak yang memiliki kekuatan misterius dan menakutkan. Sekarang, Hellsing harus menghadapi ancaman yang lebih berbahaya daripada vampir.', '2026-07-01 04:46:59', 'https://cdn.myanimelist.net/images/anime/1012/143965l.jpg'),
	(62, 'Clannad', 'Anime', '2007', 'Kyoto Animation', 'Tomoya Okazaki adalah siswa sekolah menengah tahun ketiga yang kesal dengan hidupnya. Ibunya meninggal karena kecelakaan mobil ketika dia masih muda, menyebabkan ayahnya menggunakan alkohol dan rokok. Hal ini mengakibatkan perkelahian antara keduanya sampai bahu Tomoya terluka dalam perkelahian. Sejak itu, Tomoya memiliki hubungan jauh dengan ayahnya, menyebabkan dia menjadi berandalan dari waktu ke waktu. Saat berjalan-jalan ke sekolah, dia bertemu dengan seorang gadis aneh bernama Nagisa Furukawa yang setahun lebih tua, tetapi mengulang karena sakit. Oleh karena itu, dia sering sendirian karena sebagian besar temannya sudah move on. Keduanya mulai nongkrong dan perlahan, seiring berjalannya waktu, Tomoya menemukan hidupnya bergeser ke arah yang baru.', '2026-07-01 04:49:39', 'https://cdn.myanimelist.net/images/anime/1469/158183l.jpg'),
	(63, 'Guilty Crown', 'Anime', '2011', 'Production I.G', 'Setelah terkena bencana virus, Jepang tunduk pada GHQ. Ketika siswa SMA Shu mendapatkan kekuatan aneh, ia pun terseret ke dalam gerakan pemberontakan.', '2026-07-01 04:52:38', 'https://cdn.myanimelist.net/images/anime/1566/133912l.jpg'),
	(64, 'Bakemonogatari', 'Anime', '2009', 'Shaft', 'Koyomi Araragi, seorang siswa sekolah menengah, mendapati dirinya terus-menerus bertemu dengan gadis-gadis yang menderita "keanehan" supernatural. Dia mendedikasikan dirinya untuk membantu mereka, seringkali dengan bantuan spesialis eksentrik Meme Oshino. Setiap arc berbicara tentang perjuangan unik seorang gadis yang berbeda dan penyebab misterius penderitaan mereka. Serial ini mengeksplorasi tema masa remaja, pertumbuhan pribadi, dan kompleksitas hubungan antarmanusia. Ia terkenal dengan dialognya yang jenaka, animasi gaya, dan struktur naratifnya yang unik.', '2026-07-01 04:55:10', 'https://cdn.myanimelist.net/images/anime/11/75274l.jpg'),
	(65, 'Fullmetal Alchemist: Brotherhood', 'Anime', '2009', 'Bones', 'Mengabaikan hukum alkimia merobek setengah dari anggota tubuh Edward Elric dari tubuhnya dan meninggalkan jiwa saudaranya Alphonse menempel pada baju zirah. Untuk memulihkan apa yang hilang, saudara-saudara mencari Batu Bertuah. Musuh dan sekutu – militer korup, Homunculi, dan alkemis asing – akan mengubah arah Elric bersaudara, tetapi tujuan mereka tidak akan berubah dan ikatan mereka tidak dapat dipecahkan.', '2026-07-01 04:57:41', 'https://cdn.myanimelist.net/images/anime/1208/94745l.jpg');

